 1→import { createClient } from '@supabase/supabase-js';
 2→
 3→const supabaseUrl = import.meta.env.VITE_SUPABASE_URL;
 4→const supabaseAnonKey = import.meta.env.VITE_SUPABASE_ANON_KEY;
 5→
 6→export const missingSupabaseEnvVars: string[] = [];
 7→if (!supabaseUrl) missingSupabaseEnvVars.push('VITE_SUPABASE_URL');
 8→if (!supabaseAnonKey) missingSupabaseEnvVars.push('VITE_SUPABASE_ANON_KEY');
 9→
10→export const isSupabaseConfigured = missingSupabaseEnvVars.length === 0;
11→
12→const fallbackUrl = 'http://127.0.0.1:54321';
13→const fallbackAnonKey = 'public-anon-key';
14→
15→/**
16→ * Client Supabase frontend utilise exclusivement avec la ANON KEY.
17→ */
18→export const supabase = createClient(supabaseUrl ?? fallbackUrl, supabaseAnonKey ?? fallbackAnonKey, {
19→  auth: {
20→    autoRefreshToken: true,
21→    persistSession: true,
22→    detectSessionInUrl: true,
23→  },
24→});
