 92→        const { data, error: fetchError } = await supabase
 93→          .from('prospect_assignments')
 94→          .select('id, status, notes, contacted_at, updated_at, converted_value, prospect:prospects(id, score, heat, name, location, signal)')
 95→          .eq('user_id', profile.id)
 96→          .not('status', 'eq', 'ignored')
 97→          .order('updated_at', { ascending: false });
 98→        if (fetchError) {
 99→          throw fetchError;
100→        }
101→        const rows = (data ?? []) as PipelineItem[];
102→        setItems(rows);
103→        const draft: Record<string, string> = {};
104→        rows.forEach((item) => {
105→          draft[item.id] = item.notes ?? '';
106→        });
107→        setNotesDraft(draft);
108→      } catch (caughtError) {
109→        const message = caughtError instanceof Error ? caughtError.message : 'Erreur chargement suivi relance';
110→        setError(message);
111→      } finally {
112→        setLoading(false);
113→      }
114→    };
115→
116→    void fetchAssignments();
117→  }, [profile?.id]);
