119→  /**
120→   * Met a jour un assignment de maniere optimiste.
121→   */
122→  const updateAssignment = async (
123→    item: PipelineItem,
124→    patch: Partial<Pick<PipelineItem, 'status' | 'contacted_at' | 'converted_value' | 'notes'>>,
125→  ): Promise<void> => {
126→    const previous = item;
127→    const nowIso = new Date().toISOString();
128→    const optimistic: PipelineItem = {
129→      ...item,
130→      status: patch.status ?? item.status,
131→      contacted_at: patch.contacted_at ?? item.contacted_at,
132→      converted_value: patch.converted_value ?? item.converted_value,
133→      notes: patch.notes ?? item.notes,
134→      updated_at: nowIso,
135→    };
136→
137→    setItems((current) => current.map((row) => (row.id === item.id ? optimistic : row)));
138→    if (!isSupabaseConfigured) {
139→      return;
140→    }
141→
142→    try {
143→      setSavingId(item.id);
144→      const payload: Record<string, unknown> = {
145→        updated_at: nowIso,
146→      };
147→      if (patch.status !== undefined) {
148→        payload.status = patch.status;
149→      }
150→      if (patch.contacted_at !== undefined) {
151→        payload.contacted_at = patch.contacted_at;
152→      }
153→      if (patch.converted_value !== undefined) {
154→        payload.converted_value = patch.converted_value;
155→      }
156→      if (patch.notes !== undefined) {
157→        payload.notes = patch.notes;
158→      }
159→
160→      const { error: updateError } = await supabase.from('prospect_assignments').update(payload).eq('id', item.id);
161→      if (updateError) {
162→        throw updateError;
163→      }
164→    } catch (caughtError) {
165→      setItems((current) => current.map((row) => (row.id === item.id ? previous : row)));
166→      const message = caughtError instanceof Error ? caughtError.message : 'Erreur sauvegarde';
167→      setError(message);
168→    } finally {
169→      setSavingId(null);
170→    }
171→  };
