  8→/**
  9→ * Vue de configuration des sources utilisateur.
 10→ */
 11→const SourcesPage = (): JSX.Element => {
 12→  const { profile, patchProfile } = useAuth();
 13→  const [sources, setSources] = useState<Source[]>([]);
 14→  const [loading, setLoading] = useState<boolean>(true);
 15→  const [error, setError] = useState<string | null>(null);
 16→  const [savingIds, setSavingIds] = useState<Set<string>>(new Set());
 17→  const sectorIds = useMemo(() => getProfileSectorIds(profile), [profile]);
 18→
 19→  const config = useMemo(() => profile?.sources_config ?? {}, [profile?.sources_config]);
 20→
 21→  useEffect(() => {
 22→    if (sectorIds.length === 0) {
 23→      setSources([]);
 24→      setLoading(false);
 25→      return;
 26→    }
 27→    if (!isSupabaseConfigured) {
 28→      setSources(demoSources.filter((source) => sectorIds.includes(source.sector_id)));
 29→      setLoading(false);
 30→      return;
 31→    }
 32→    const fetchSources = async (): Promise<void> => {
 33→      try {
 34→        setLoading(true);
 35→        const { data, error: fetchError } = await supabase
 36→          .from('sources')
 37→          .select('*')
 38→          .in('sector_id', sectorIds)
 39→          .order('name', { ascending: true });
 40→        if (fetchError) {
 41→          throw fetchError;
 42→        }
 43→        setSources((data ?? []) as Source[]);
 44→      } catch (caughtError) {
 45→        const message = caughtError instanceof Error ? caughtError.message : 'Erreur chargement sources';
 46→        setError(message);
 47→      } finally {
 48→        setLoading(false);
 49→      }
 50→    };
 51→    void fetchSources();
 52→  }, [sectorIds]);
 53→
 54→  /**
 55→   * Active/desactive une source uniquement au niveau user.
 56→   */
 57→  const toggleSource = async (sourceId: string, enabled: boolean): Promise<void> => {
 58→    if (!profile) {
 59→      return;
 60→    }
 61→    const nextConfig = { ...config, [sourceId]: enabled };
 62→    setSavingIds((current) => new Set([...current, sourceId]));
 63→    const saved = await patchProfile({ sources_config: nextConfig });
 64→    if (!saved) {
 65→      setError('Sauvegarde impossible');
 66→    }
 67→    setSavingIds((current) => {
 68→      const next = new Set(current);
 69→      next.delete(sourceId);
 70→      return next;
 71→    });
 72→  };
 73→
 74→  return (
 75→    <div className="space-y-4 px-4 md:px-0">
 76→      <header>
 77→        <h1 className="font-outfit text-3xl font-bold">Ciblage par sources</h1>
 78→        <p className="text-sm text-slate-300">Choisissez les canaux qui alimentent votre liste de prospects.</p>
 79→      </header>
 80→
 81→      {error ? <div className="rounded-lg border border-red-500/40 bg-red-500/10 p-3 text-sm text-red-300">{error}</div> : null}
 82→
 83→      <section className="space-y-3">
 84→        {loading
 85→          ? Array.from({ length: 5 }).map((_, index) => (
 86→              <div key={`source-skeleton-${index}`} className="h-24 animate-pulse rounded-xl border border-leadradar-border bg-leadradar-card" />
 87→            ))
 88→          : sources.map((source) => {
 89→              const activeForUser = config[source.id] ?? true;
 90→              const updating = savingIds.has(source.id);
 91→              return (
 92→                <article
 93→                  key={source.id}
 94→                  className="flex flex-col gap-4 rounded-xl border border-leadradar-border bg-leadradar-card p-4 md:flex-row md:items-center md:justify-between"
 95→                >
 96→                  <div className="flex items-center gap-3">
 97→                    <div className="grid h-12 w-12 place-items-center rounded-xl border border-leadradar-border bg-[#0F172A] text-xl">
 98→                      {source.icon ?? 'SRC'}
 99→                    </div>
100→                    <div>
101→                      <h2 className="font-outfit text-lg font-semibold">{source.name}</h2>
102→                      <p className="text-sm text-slate-300">
103→                        {source.data_type ?? source.description ?? 'Source metier'} | {source.scan_frequency}
104→                      </p>
105→                    </div>
106→                  </div>
107→                  <div className="flex items-center gap-3">
108→                    <span
109→                      className={`rounded-full px-3 py-1 text-xs ${
110→                        activeForUser ? 'bg-emerald-500/15 text-emerald-300' : 'bg-slate-700/40 text-slate-300'
111→                      }`}
112→                    >
113→                      {activeForUser ? 'Actif' : 'Inactif'}
114→                    </span>
115→                    <button
116→                      type="button"
117→                      disabled={updating}
118→                      onClick={() => {
119→                        void toggleSource(source.id, !activeForUser);
120→                      }}
121→                      className={`relative h-7 w-12 rounded-full transition ${activeForUser ? 'bg-emerald-500' : 'bg-slate-600'}`}
122→                    >
123→                      <span
124→                        className={`absolute top-1 h-5 w-5 rounded-full bg-white transition ${
125→                          activeForUser ? 'right-1' : 'left-1'
126→                        }`}
127→                      />
128→                    </button>
129→                  </div>
130→                </article>
131→              );
132→            })}
133→      </section>
134→
135→      <section className="rounded-xl border border-dashed border-leadradar-border bg-[#0F172A] p-4">
136→        <h3 className="font-outfit text-lg font-semibold">Ajouter une source</h3>
137→        <p className="mt-1 text-sm text-slate-300">Demandez une source de donnees specifique a votre marche.</p>
138→        <a
139→          href="mailto:support@leadradar.io?subject=Suggestion%20source%20LeadRadar"
140→          className="mt-3 inline-flex rounded-lg border border-leadradar-border px-3 py-2 text-sm text-slate-200"
141→        >
142→          Envoyer une suggestion
143→        </a>
144→      </section>
145→    </div>
146→  );
147→};
