 1→import { useEffect, useMemo, useState } from 'react';
 2→
 3→interface ScoreRingProps {
 4→  score: number;
 5→  size?: number;
 6→}
 7→
 8→/**
 9→ * Anneau SVG anime representant le score prospect.
10→ */
11→export const ScoreRing = ({ score, size = 56 }: ScoreRingProps): JSX.Element => {
12→  const [animatedScore, setAnimatedScore] = useState<number>(0);
13→  const safeScore = Math.max(0, Math.min(100, score));
14→  const stroke = Math.max(4, Math.round(size * 0.1));
15→  const radius = (size - stroke) / 2;
16→  const circumference = 2 * Math.PI * radius;
17→
18→  const color = useMemo(() => {
19→    if (safeScore >= 90) {
20→      return '#EF4444';
21→    }
22→    if (safeScore >= 75) {
23→      return '#F97316';
24→    }
25→    if (safeScore >= 50) {
26→      return '#F59E0B';
27→    }
28→    return '#64748B';
29→  }, [safeScore]);
30→
31→  useEffect(() => {
32→    const timer = window.setTimeout(() => setAnimatedScore(safeScore), 30);
33→    return () => window.clearTimeout(timer);
34→  }, [safeScore]);
35→
36→  const offset = circumference - (animatedScore / 100) * circumference;
37→
38→  return (
39→    <div className="relative inline-flex items-center justify-center" style={{ width: size, height: size }}>
40→      <svg width={size} height={size} className="-rotate-90">
41→        <circle
42→          cx={size / 2}
43→          cy={size / 2}
44→          r={radius}
45→          fill="transparent"
46→          stroke="#1E293B"
47→          strokeWidth={stroke}
48→        />
49→        <circle
50→          cx={size / 2}
51→          cy={size / 2}
52→          r={radius}
53→          fill="transparent"
54→          stroke={color}
55→          strokeWidth={stroke}
56→          strokeLinecap="round"
57→          strokeDasharray={circumference}
58→          strokeDashoffset={offset}
59→          style={{ transition: 'stroke-dashoffset 650ms ease-out' }}
60→        />
61→      </svg>
62→      <span className="absolute text-sm font-bold text-white">{safeScore}</span>
63→    </div>
64→  );
65→};
