 15→/**
 16→ * Modale edition / copie / envoi email de message d'approche.
 17→ */
 18→export const ApproachModal = ({
 19→  isOpen,
 20→  initialMessage,
 21→  sectorId,
 22→  rawData,
 23→  onClose,
 24→  onApplyMessage,
 25→  onCopy,
 26→}: ApproachModalProps): JSX.Element | null => {
 27→  const [tone, setTone] = useState<ApproachTone>('professional');
 28→  const [message, setMessage] = useState<string>(initialMessage);
 29→  const [copied, setCopied] = useState<boolean>(false);
 30→  const [loading, setLoading] = useState<boolean>(false);
 31→  const [error, setError] = useState<string | null>(null);
 32→
 33→  useEffect(() => {
 34→    if (isOpen) {
 35→      setMessage(initialMessage);
 36→      setCopied(false);
 37→      setError(null);
 38→    }
 39→  }, [initialMessage, isOpen]);
 40→
 41→  const toneLabel = useMemo(() => {
 42→    if (tone === 'friendly') {
 43→      return 'Amical';
 44→    }
 45→    if (tone === 'direct') {
 46→      return 'Direct';
 47→    }
 48→    return 'Professionnel';
 49→  }, [tone]);
 50→
 51→  if (!isOpen) {
 52→    return null;
 53→  }
 54→
 55→  /**
 56→   * Regénère le texte via la fonction analyze en mode message-only.
 57→   */
 58→  const regenerate = async (nextTone: ApproachTone): Promise<void> => {
 59→    try {
 60→      setLoading(true);
 61→      setError(null);
 62→      setTone(nextTone);
 63→      const { data, error: invokeError } = await supabase.functions.invoke('analyze', {
 64→        body: {
 65→          sector: sectorId,
 66→          source: 'manual',
 67→          raw_data: rawData,
 68→          approach_tone: nextTone,
 69→          message_only: true,
