 74→      }
 75→      const nextMessage = String((data as { approach_message?: string } | null)?.approach_message ?? '').trim();
 76→      if (!nextMessage) {
 77→        throw new Error('Reponse vide');
 78→      }
 79→      setMessage(nextMessage);
 80→      onApplyMessage(nextMessage);
 81→    } catch (caughtError) {
 82→      const fallback =
 83→        nextTone === 'direct'
 84→          ? `${initialMessage}\n\nPS: Je vous propose un echange de 15 minutes cette semaine.`
 85→          : nextTone === 'friendly'
 86→            ? `${initialMessage}\n\nAu plaisir d'en discuter avec vous, en toute simplicite.`
 87→            : initialMessage;
 88→      setMessage(fallback);
