105→    }
106→  };
107→
108→  const emailUrl = `mailto:?subject=${encodeURIComponent('[LeadRadar] Proposition de contact')}&body=${encodeURIComponent(
109→    message,
110→  )}`;
111→
112→  return (
113→    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/70 p-4">
114→      <div className="h-full w-full overflow-hidden rounded-2xl border border-leadradar-border bg-[#0B0F1A] md:h-auto md:max-h-[90vh] md:max-w-4xl">
115→        <div className="flex items-center justify-between border-b border-leadradar-border px-5 py-4">
116→          <h3 className="font-outfit text-xl font-semibold">Email auto - {toneLabel}</h3>
117→          <button type="button" onClick={onClose} className="rounded-md border border-leadradar-border px-3 py-1 text-sm">
118→            Fermer
119→          </button>
120→        </div>
121→        <div className="grid h-[calc(100%-65px)] grid-cols-1 gap-4 overflow-auto p-5 md:grid-cols-2">
122→          <div className="space-y-3">
123→            <div className="flex flex-wrap gap-2">
124→              {([
125→                ['professional', 'Professionnel'],
126→                ['friendly', 'Amical'],
127→                ['direct', 'Direct'],
128→              ] as Array<[ApproachTone, string]>).map(([value, label]) => (
129→                <button
130→                  key={value}
131→                  type="button"
132→                  onClick={() => {
133→                    void regenerate(value);
134→                  }}
135→                  disabled={loading}
136→                  className={`rounded-full border px-3 py-1 text-sm transition ${
137→                    tone === value
138→                      ? 'border-emerald-500 bg-emerald-500/15 text-emerald-300'
139→                      : 'border-leadradar-border text-slate-300 hover:text-white'
140→                  }`}
141→                >
142→                  {label}
143→                </button>
144→              ))}
145→            </div>
146→            <textarea
147→              value={message}
148→              onChange={(event) => {
149→                setMessage(event.target.value);
150→                onApplyMessage(event.target.value);
