158→                  void copyMessage();
159→                }}
160→                className="rounded-lg bg-emerald-500 px-3 py-2 text-sm font-semibold text-emerald-950"
161→              >
162→                Copier
163→              </button>
164→              <a href={emailUrl} className="rounded-lg border border-leadradar-border px-3 py-2 text-sm text-slate-200">
165→                Envoyer par email
