399→        window.localStorage.removeItem(DEMO_AUTH_STORAGE_KEY);
400→        window.localStorage.removeItem(DEMO_PROFILE_STORAGE_KEY);
401→      }
402→      return;
403→    }
404→    setLoading(true);
405→    setError(null);
406→    const { error: logoutError } = await supabase.auth.signOut();
407→    if (logoutError) {
408→      setError(logoutError.message);
409→    }
410→    setLoading(false);
411→  }, []);
412→
413→  /**
414→   * Lance le flux de reset mot de passe Supabase.
415→   */
416→  const resetPassword = useCallback(async (email: string): Promise<boolean> => {
417→    if (!isSupabaseConfigured) {
418→      if (!email.trim()) {
419→        setError('Email requis.');
420→        return false;
421→      }
422→      setError('Mode demo: reset indisponible sans Supabase.');
423→      return true;
424→    }
425→    try {
426→      setError(null);
427→      const { error: resetError } = await supabase.auth.resetPasswordForEmail(email);
428→      if (resetError) {
429→        throw resetError;
430→      }
431→      return true;
432→    } catch (resetCaught) {
433→      const message = resetCaught instanceof Error ? resetCaught.message : 'Reset impossible';
434→      setError(message);
435→      return false;
436→    }
437→  }, []);
438→
439→  const clearError = useCallback(() => setError(null), []);
440→
441→  const value = useMemo<AuthContextValue>(
442→    () => ({
443→      user,
444→      profile,
445→      loading,
446→      error,
447→      login,
448→      signup,
449→      logout,
450→      resetPassword,
451→      clearError,
452→      refreshProfile,
453→      patchProfile,
454→    }),
455→    [clearError, error, loading, login, logout, patchProfile, profile, refreshProfile, resetPassword, signup, user],
456→  );
457→
458→  return <AuthContext.Provider value={value}>{children}</AuthContext.Provider>;
459→};
