  1→import { useCallback, useEffect, useMemo, useState } from 'react';
  2→import { PROSPECTS_PAGE_SIZE } from '../lib/constants';
  3→import { demoRadarProspects } from '../lib/demo-data';
  4→import { isSupabaseConfigured, supabase } from '../lib/supabase';
  5→import type { HeatCounters, HeatLevel } from '../lib/types';
  6→import { getProfileSectorIds } from '../utils/sector-targeting';
  7→import { useAuth } from './useAuth';
  8→
  9→interface RadarProspectRow {
 10→  id: string;
 11→  score: number;
 12→  heat: HeatLevel;
 13→  signal: string;
 14→  name: string;
 15→  location: string | null;
 16→  details_json?: Record<string, unknown>;
 17→  raw_data_json?: Record<string, unknown>;
 18→  detected_at: string;
 19→  source_id: string | null;
 20→  source_name: string | null;
 21→  source_icon: string | null;
 22→  assignment_id: string | null;
 23→  assignment_status: string | null;
 24→}
 25→
 26→interface UseProspectsResult {
 27→  prospects: RadarProspectRow[];
 28→  counters: HeatCounters;
 29→  loading: boolean;
 30→  loadingMore: boolean;
 31→  error: string | null;
 32→  hasMore: boolean;
 33→  newProspectIds: string[];
 34→  fetchMore: () => Promise<void>;
 35→  refetch: () => Promise<void>;
 36→}
 37→
 38→/**
 39→ * Charge le flux Radar avec pagination + realtime.
 40→ */
 41→export const useProspects = (heatFilter: HeatLevel | 'all' = 'all'): UseProspectsResult => {
 42→  const { profile } = useAuth();
 43→  const sectorIds = useMemo(() => getProfileSectorIds(profile), [profile]);
 44→  const sectorIdsKey = useMemo(() => sectorIds.join('|'), [sectorIds]);
 45→  const [prospects, setProspects] = useState<RadarProspectRow[]>([]);
 46→  const [counters, setCounters] = useState<HeatCounters>({
 47→    total: 0,
 48→    burning: 0,
 49→    hot: 0,
 50→    warm: 0,
 51→    cold: 0,
 52→  });
 53→  const [loading, setLoading] = useState<boolean>(true);
 54→  const [loadingMore, setLoadingMore] = useState<boolean>(false);
 55→  const [error, setError] = useState<string | null>(null);
 56→  const [offset, setOffset] = useState<number>(0);
 57→  const [hasMore, setHasMore] = useState<boolean>(true);
 58→  const [newProspectIds, setNewProspectIds] = useState<string[]>([]);
 59→
 60→  const fetchCounters = useCallback(async (): Promise<void> => {
 61→    if (!isSupabaseConfigured) {
 62→      const total = demoRadarProspects.length;
 63→      const burning = demoRadarProspects.filter((item) => item.heat === 'burning').length;
 64→      const hot = demoRadarProspects.filter((item) => item.heat === 'hot').length;
 65→      const warm = demoRadarProspects.filter((item) => item.heat === 'warm').length;
 66→      const cold = demoRadarProspects.filter((item) => item.heat === 'cold').length;
 67→      setCounters({ total, burning, hot, warm, cold });
 68→      return;
 69→    }
 70→    const { data, error: rpcError } = await supabase.rpc('get_user_prospect_counters');
 71→    if (rpcError) {
 72→      throw rpcError;
 73→    }
 74→    const row = (Array.isArray(data) ? data[0] : data) as Partial<HeatCounters> | undefined;
 75→    setCounters({
 76→      total: Number(row?.total ?? 0),
 77→      burning: Number(row?.burning ?? 0),
 78→      hot: Number(row?.hot ?? 0),
 79→      warm: Number(row?.warm ?? 0),
 80→      cold: Number(row?.cold ?? 0),
 81→    });
 82→  }, []);
 83→
 84→  const fetchPage = useCallback(
 85→    async (targetOffset: number, append: boolean): Promise<void> => {
 86→      if (!isSupabaseConfigured) {
 87→        const targetsKnownInDemo = sectorIds.some((sectorId) => ['immobilier', 'coaching', 'btp'].includes(sectorId));
 88→        const scopedBySector =
 89→          sectorIds.length === 0
 90→            ? []
 91→            : !targetsKnownInDemo || sectorIds.includes('immobilier')
 92→              ? demoRadarProspects
 93→              : [];
 94→        const filtered = (heatFilter === 'all' ? scopedBySector : scopedBySector.filter((item) => item.heat === heatFilter)).sort(
 95→          (a, b) => b.score - a.score,
 96→        );
 97→        const rows = filtered.slice(targetOffset, targetOffset + PROSPECTS_PAGE_SIZE);
 98→        setProspects((current) => {
 99→          if (!append) {
100→            return rows;
101→          }
102→          return [...current, ...rows];
103→        });
104→        setHasMore(targetOffset + PROSPECTS_PAGE_SIZE < filtered.length);
105→        return;
106→      }
107→      if (sectorIds.length === 0) {
108→        setLoading(false);
109→        return;
110→      }
111→      const pHeat = heatFilter === 'all' ? null : heatFilter;
112→      const { data, error: rpcError } = await supabase.rpc('get_user_prospects', {
113→        p_limit: PROSPECTS_PAGE_SIZE,
114→        p_offset: targetOffset,
115→        p_heat: pHeat,
116→      });
117→      if (rpcError) {
118→        throw rpcError;
119→      }
120→      const rows = (data ?? []) as RadarProspectRow[];
121→      setProspects((current) => {
122→        if (!append) {
123→          return rows;
124→        }
125→        const deduped = new Map<string, RadarProspectRow>();
126→        [...current, ...rows].forEach((item) => deduped.set(item.id, item));
127→        return [...deduped.values()].sort((a, b) => b.score - a.score);
128→      });
129→      setHasMore(rows.length === PROSPECTS_PAGE_SIZE);
130→    },
131→    [heatFilter, sectorIds, sectorIdsKey],
132→  );
133→
134→  const refetch = useCallback(async (): Promise<void> => {
135→    try {
136→      setLoading(true);
137→      setError(null);
138→      setOffset(0);
139→      await Promise.all([fetchPage(0, false), fetchCounters()]);
140→    } catch (refetchError) {
141→      const message = refetchError instanceof Error ? refetchError.message : 'Erreur chargement prospects';
142→      setError(message);
143→    } finally {
144→      setLoading(false);
145→    }
146→  }, [fetchCounters, fetchPage]);
147→
148→  const fetchMore = useCallback(async (): Promise<void> => {
149→    if (!hasMore || loadingMore || loading) {
150→      return;
151→    }
152→    try {
153→      setLoadingMore(true);
154→      const nextOffset = offset + PROSPECTS_PAGE_SIZE;
155→      await fetchPage(nextOffset, true);
156→      setOffset(nextOffset);
157→    } catch (fetchMoreError) {
158→      const message = fetchMoreError instanceof Error ? fetchMoreError.message : 'Erreur pagination';
159→      setError(message);
160→    } finally {
161→      setLoadingMore(false);
162→    }
163→  }, [fetchPage, hasMore, loading, loadingMore, offset]);
164→
165→  useEffect(() => {
166→    void refetch();
167→  }, [refetch]);
168→
169→  useEffect(() => {
170→    if (!isSupabaseConfigured) {
171→      return;
172→    }
173→    if (sectorIds.length === 0) {
174→      return;
175→    }
176→    const channel = supabase
177→      .channel(`prospects-live-${profile?.id ?? 'anonymous'}-${sectorIdsKey}`)
178→      .on(
179→        'postgres_changes',
180→        {
181→          event: 'INSERT',
182→          schema: 'public',
183→          table: 'prospects',
184→        },
185→        (payload) => {
186→          const inserted = payload.new as { id: string; heat: HeatLevel; score: number; sector_id?: string } | null;
187→          if (!inserted) {
188→            return;
189→          }
190→          const insertedSector = String(inserted.sector_id ?? '');
191→          if (!sectorIds.includes(insertedSector)) {
192→            return;
193→          }
194→          setNewProspectIds((current) => [inserted.id, ...current].slice(0, 5));
195→          void refetch();
196→          window.setTimeout(() => {
197→            setNewProspectIds((current) => current.filter((id) => id !== inserted.id));
198→          }, 4500);
199→        },
200→      )
201→      .subscribe();
202→
203→    return () => {
204→      void supabase.removeChannel(channel);
205→    };
206→  }, [profile?.id, refetch, sectorIds, sectorIdsKey]);
207→
208→  const sortedProspects = useMemo(() => [...prospects].sort((a, b) => b.score - a.score), [prospects]);
209→
210→  return {
211→    prospects: sortedProspects,
212→    counters,
213→    loading,
214→    loadingMore,
215→    error,
216→    hasMore,
217→    newProspectIds,
218→    fetchMore,
219→    refetch,
220→  };
221→};
