 47→/**
 48→ * Hook de detail prospect avec mise a jour optimiste.
 49→ */
 50→export const useProspectDetail = (prospectId: string): ProspectDetailState => {
 51→  const { user } = useAuth();
 52→  const [prospect, setProspect] = useState<ProspectDetail | null>(null);
 53→  const [loading, setLoading] = useState<boolean>(true);
 54→  const [error, setError] = useState<string | null>(null);
 55→
 56→  const refetch = useCallback(async (): Promise<void> => {
 57→    if (!isSupabaseConfigured) {
 58→      const sourceMap = new Map<string, Source>(demoSources.map((source) => [source.id, source]));
 59→      const found = demoProspects.find((item) => item.id === prospectId) ?? null;
 60→      if (!found) {
 61→        setProspect(null);
 62→        setLoading(false);
 63→        return;
 64→      }
 65→      const assignment = demoAssignments.find((item) => item.prospect_id === prospectId && item.user_id === user?.id) ?? null;
 66→      setProspect({
 67→        ...found,
 68→        source: found.source_id ? sourceMap.get(found.source_id) ?? null : null,
 69→        assignment,
 70→      });
 71→      setLoading(false);
 72→      return;
 73→    }
 74→    if (!user || !prospectId) {
 75→      setLoading(false);
 76→      return;
 77→    }
 78→    try {
 79→      setLoading(true);
 80→      setError(null);
 81→      const { data, error: queryError } = await supabase
 82→        .from('prospects')
 83→        .select('*, source:sources(*), assignments:prospect_assignments!left(*)')
 84→        .eq('id', prospectId)
 85→        .maybeSingle<ProspectQueryRow>();
 86→      if (queryError) {
 87→        throw queryError;
 88→      }
 89→      if (!data) {
 90→        setProspect(null);
 91→        return;
 92→      }
 93→      const assignment = (data.assignments ?? []).find((item) => item.user_id === user.id) ?? null;
 94→      setProspect({
 95→        ...data,
 96→        assignment,
 97→      });
 98→    } catch (fetchError) {
 99→      const message = fetchError instanceof Error ? fetchError.message : 'Erreur detail prospect';
100→      setError(message);
101→    } finally {
102→      setLoading(false);
103→    }
104→  }, [prospectId, user]);
105→
106→  useEffect(() => {
107→    void refetch();
108→  }, [refetch]);
109→
110→  /**
111→   * Met a jour le statut assignment avec optimistic update.
112→   */
113→  const updateStatus = useCallback(
114→    async (status: AssignmentStatus, convertedValue?: number | null): Promise<boolean> => {
115→      if (!prospect) {
116→        return false;
117→      }
118→      if (!isSupabaseConfigured) {
119→        const nowIso = new Date().toISOString();
120→        const previous = prospect.assignment;
121→        const optimistic: ProspectAssignment = {
122→          id: previous?.id ?? `demo-${prospect.id}`,
123→          prospect_id: prospect.id,
124→          user_id: user?.id ?? 'demo-user',
125→          status,
126→          notes: previous?.notes ?? null,
127→          contacted_at: status === 'contacted' ? nowIso : previous?.contacted_at ?? null,
128→          converted_at: status === 'won' ? nowIso : previous?.converted_at ?? null,
129→          converted_value: status === 'won' ? convertedValue ?? previous?.converted_value ?? null : null,
130→          created_at: previous?.created_at ?? nowIso,
131→          updated_at: nowIso,
132→        };
133→        setProspect((current) => (current ? { ...current, assignment: optimistic } : current));
134→        return true;
135→      }
136→      if (!user) {
137→        return false;
138→      }
139→      const previous = prospect.assignment;
140→      const nowIso = new Date().toISOString();
141→      const optimistic: ProspectAssignment = {
142→        id: previous?.id ?? crypto.randomUUID(),
143→        prospect_id: prospect.id,
144→        user_id: user.id,
145→        status,
146→        notes: previous?.notes ?? null,
147→        contacted_at: status === 'contacted' ? nowIso : previous?.contacted_at ?? null,
148→        converted_at: status === 'won' ? nowIso : previous?.converted_at ?? null,
149→        converted_value: status === 'won' ? convertedValue ?? previous?.converted_value ?? null : null,
150→        created_at: previous?.created_at ?? nowIso,
151→        updated_at: nowIso,
152→      };
153→      setProspect((current) => (current ? { ...current, assignment: optimistic } : current));
154→
155→      const payload = {
156→        prospect_id: prospect.id,
157→        user_id: user.id,
158→        status,
159→        contacted_at: optimistic.contacted_at,
160→        converted_at: optimistic.converted_at,
161→        converted_value: optimistic.converted_value,
162→        updated_at: nowIso,
163→      };
164→      const { error: upsertError } = await supabase.from('prospect_assignments').upsert(payload, {
165→        onConflict: 'prospect_id,user_id',
166→      });
167→      if (upsertError) {
168→        setProspect((current) => (current ? { ...current, assignment: previous ?? null } : current));
169→        setError(upsertError.message);
170→        return false;
171→      }
172→      return true;
173→    },
174→    [prospect, user],
175→  );
176→
177→  /**
178→   * Met a jour les notes assignment.
179→   */
180→  const updateNotes = useCallback(
181→    async (notes: string): Promise<boolean> => {
182→      if (!prospect?.assignment) {
183→        return false;
184→      }
185→      if (!isSupabaseConfigured) {
186→        setProspect((current) =>
187→          current?.assignment
188→            ? {
189→                ...current,
190→                assignment: { ...current.assignment, notes, updated_at: new Date().toISOString() },
191→              }
192→            : current,
193→        );
194→        return true;
195→      }
196→      if (!user) {
197→        return false;
198→      }
199→      const previousNotes = prospect.assignment.notes;
200→      setProspect((current) =>
201→        current?.assignment
202→          ? {
203→              ...current,
204→              assignment: { ...current.assignment, notes, updated_at: new Date().toISOString() },
205→            }
206→          : current,
207→      );
208→      const { error: updateError } = await supabase
209→        .from('prospect_assignments')
210→        .update({ notes })
211→        .eq('id', prospect.assignment.id);
212→      if (updateError) {
213→        setProspect((current) =>
214→          current?.assignment
215→            ? {
216→                ...current,
217→                assignment: { ...current.assignment, notes: previousNotes },
218→              }
219→            : current,
220→        );
221→        setError(updateError.message);
222→        return false;
223→      }
224→      return true;
225→    },
226→    [prospect?.assignment, user],
227→  );
228→
229→  /**
230→   * Copie texte avec fallback mobile.
231→   */
232→  const copyApproachMessage = useCallback(async (text: string): Promise<boolean> => {
233→    try {
234→      if (navigator.clipboard && window.isSecureContext) {
235→        await navigator.clipboard.writeText(text);
236→        return true;
237→      }
238→      const textarea = document.createElement('textarea');
239→      textarea.value = text;
240→      textarea.style.position = 'fixed';
241→      textarea.style.left = '-9999px';
242→      document.body.appendChild(textarea);
243→      textarea.focus();
244→      textarea.select();
245→      const success = document.execCommand('copy');
246→      document.body.removeChild(textarea);
247→      return success;
248→    } catch {
249→      return false;
250→    }
251→  }, []);
252→
253→  return useMemo(
254→    () => ({
255→      prospect,
256→      loading,
257→      error,
258→      updateStatus,
259→      updateNotes,
260→      copyApproachMessage,
261→      refetch,
262→    }),
263→    [copyApproachMessage, error, loading, prospect, refetch, updateNotes, updateStatus],
264→  );
265→};
