  1→import { findSectorOptionById } from '../lib/constants';
  2→import type { Profile, SectorTarget, SectorTargetOption } from '../lib/types';
  3→
  4→interface ProfileSectorShape {
  5→  sector_id: string | null;
  6→  sector_selected_at?: string | null;
  7→  target_sector_ids?: string[] | null;
  8→  target_sectors_json?: SectorTarget[] | null;
  9→}
 10→
 11→/**
 12→ * Projette une option selectable en payload profile.
 13→ */
 14→export const sectorTargetFromOption = (optionItem: SectorTargetOption): SectorTarget => ({
 15→  id: optionItem.id,
 16→  label: optionItem.label,
 17→  section: optionItem.section,
 18→  subsection: optionItem.subsection,
 19→});
 20→
 21→/**
 22→ * Dedoublonne les secteurs selon id, en conservant l'ordre de selection.
 23→ */
 24→export const dedupeSectorTargets = (targets: SectorTarget[]): SectorTarget[] => {
 25→  const map = new Map<string, SectorTarget>();
 26→  targets.forEach((target) => {
 27→    const id = String(target.id ?? '').trim();
 28→    if (!id || map.has(id)) {
 29→      return;
 30→    }
 31→    map.set(id, {
 32→      id,
 33→      label: String(target.label ?? '').trim() || id,
 34→      section: String(target.section ?? '').trim() || 'Autres',
 35→      subsection: String(target.subsection ?? '').trim() || 'General',
 36→    });
 37→  });
 38→  return [...map.values()];
 39→};
 40→
 41→/**
 42→ * Construit des targets a partir d'ids secteur.
 43→ */
 44→export const sectorTargetsFromIds = (sectorIds: string[]): SectorTarget[] => {
 45→  const projected = sectorIds.map((sectorId) => {
 46→    const found = findSectorOptionById(sectorId);
 47→    if (found) {
 48→      return sectorTargetFromOption(found);
 49→    }
 50→    return {
 51→      id: sectorId,
 52→      label: sectorId,
 53→      section: 'Autres',
 54→      subsection: 'General',
 55→    } satisfies SectorTarget;
 56→  });
 57→  return dedupeSectorTargets(projected);
 58→};
 59→
 60→/**
 61→ * Retourne la liste secteur effectivement configuree sur un profil.
 62→ */
 63→export const getProfileSectorTargets = (profile: ProfileSectorShape | null | undefined): SectorTarget[] => {
 64→  if (!profile) {
 65→    return [];
 66→  }
 67→  const fromJson = dedupeSectorTargets([...(profile.target_sectors_json ?? [])]);
 68→  if (fromJson.length > 0) {
 69→    return fromJson;
 70→  }
 71→
 72→  const fromIds = sectorTargetsFromIds((profile.target_sector_ids ?? []).filter((value): value is string => Boolean(value?.trim())));
 73→  if (fromIds.length > 0) {
 74→    return fromIds;
 75→  }
 76→
 77→  if (profile.sector_id?.trim()) {
 78→    return sectorTargetsFromIds([profile.sector_id]);
 79→  }
 80→  return [];
 81→};
 82→
 83→/**
 84→ * Retourne uniquement les identifiants secteur actifs.
 85→ */
 86→export const getProfileSectorIds = (profile: ProfileSectorShape | null | undefined): string[] =>
 87→  getProfileSectorTargets(profile).map((target) => target.id);
 88→
 89→/**
 90→ * Indique si l'onboarding secteur est complete.
 91→ */
 92→export const hasProfileSectorTargets = (profile: ProfileSectorShape | null | undefined): boolean =>
 93→  getProfileSectorIds(profile).length > 0;
 94→
 95→/**
 96→ * Construit le patch profile pour mettre a jour le ciblage secteur.
 97→ */
 98→export const buildProfileSectorPatch = (
 99→  currentProfile: ProfileSectorShape | null | undefined,
100→  targets: SectorTarget[],
101→): Partial<Profile> => {
102→  const dedupedTargets = dedupeSectorTargets(targets);
103→  const ids = dedupedTargets.map((target) => target.id);
104→  const nowIso = new Date().toISOString();
105→  return {
106→    sector_id: ids[0] ?? null,
107→    target_sector_ids: ids,
108→    target_sectors_json: dedupedTargets,
109→    sector_selected_at: ids.length > 0 ? currentProfile?.sector_selected_at ?? nowIso : null,
110→    updated_at: nowIso,
111→  };
112→};
