12→/**
13→ * Retourne une date relative courte en francais.
14→ */
15→export const formatRelativeDate = (isoDate: string): string => {
16→  const date = new Date(isoDate).getTime();
17→  const now = Date.now();
18→  const diffMs = now - date;
19→  const hour = 3_600_000;
20→  const day = 86_400_000;
21→  if (diffMs < hour) {
22→    const mins = Math.max(1, Math.floor(diffMs / 60_000));
23→    return `Il y a ${mins} min`;
24→  }
25→  if (diffMs < day) {
26→    const hours = Math.floor(diffMs / hour);
27→    return `Il y a ${hours}h`;
28→  }
29→  if (diffMs < day * 2) {
30→    return 'Hier';
31→  }
32→  const days = Math.floor(diffMs / day);
33→  return `Il y a ${days} jours`;
34→};
